explanation_structured.related_decision_tree:
flowchart TD
  Start([完成 1L Pac/Carbo × 6 CR/PR]) --> BevUsed{1L 是否用 Bev?}
  BevUsed -->|未用 Bev| BevNo{BRCA/HRD?}
  BevUsed -->|有用 Bev| BevYes{BRCA/HRD?}
  BevNo -->|BRCA P/LP ✅| Ans[**Olaparib 單藥 Cat 1**<br>SOLO-1 path]
  BevNo -->|HRD+ non-BRCA| Nira1[Niraparib/Rucaparib<br>Olap 單藥 Cat 2B]
  BevNo -->|HRP/Unknown| Nira2[Niraparib/Rucaparib]
  BevYes -->|BRCA P/LP| OlapBev[Olap + Bev Cat 1<br>PAOLA-1]
  classDef ans fill:#d4edda,stroke:#27ae60,stroke-width:3px;
  class Ans ans;

flowchart TD
  Start([1L 已用 Bev<br>HRD+ non-BRCA<br>response CR/PR]) --> Ans[**Olap + Bev Cat 1**<br>PAOLA-1 path<br>Olap 300 mg BID × 2 yr<br>Bev 15 mg/kg Q3W to 22 cycles total]
  classDef ans fill:#d4edda,stroke:#27ae60,stroke-width:3px;
  class Ans ans;

flowchart TD
  Recur([Recurrent OC]) --> PFI{Platinum-Free Interval}
  PFI -->|>6 月| PS[**Platinum-Sensitive**<br>重新挑戰 platinum<br>Carbo/PLD 或 Carbo/Gem±Bev]
  PFI -->|≤6 月| PR[Platinum-Resistant<br>non-platinum 後線]
  PS --> Response{Response CR/PR?}
  Response -->|Yes + BRCA P/LP| SOLO2[**SOLO-2 Olaparib maintenance** ✅<br>⚠️ PARPi 單藥 active treatment 已撤銷]
  Response -->|Yes + HRD+| ARIEL3[ARIEL3 Rucaparib<br>OR NOVA Niraparib maintenance]
  classDef ans fill:#d4edda,stroke:#27ae60,stroke-width:3px;
  class SOLO2 ans;
  classDef removed fill:#f8d7da,stroke:#c0392b,stroke-dasharray:5 5;

flowchart TD
  PR([Platinum-Resistant Recurrent]) --> FRa{FRα IHC<br>VENTANA assay}
  FRa -->|≥75% High| Mono[**Mirvetuximab 單藥** ✅<br>MIRASOL OS 16.5 vs 12.8 月<br>HR 0.67]
  FRa -->|≥50% 或 ≥25%| Combo[Mirvetuximab + Bev<br>Cat 2B v.3.2025 新]
  FRa -->|<25%| Other[其他選項<br>nab-Pac+Relacorilant /<br>單藥化療 / T-DXd if HER2+]
  classDef ans fill:#d4edda,stroke:#27ae60,stroke-width:3px;
  class Mono ans;

flowchart TD
  Diag([年輕女性+高血鈣+卵巢腫塊<br>三聯徵]) --> Path[病理確認 SCCOHT]
  Path --> SMARCA4[**Germline SMARCA4 testing 必做** ✅]
  SMARCA4 --> Chemo[一線化療<br>VPCBAE / PAVEP / BEP]
  Chemo --> Consol[**Auto-SCT consolidation** ✅<br>轉介幹細胞中心<br>高劑量化療]
  Consol --> Fert{Germline SMARCA4 status?}
  Fert -->|陰性 + 強烈意願| FS[考慮 fertility-sparing<br>充分諮詢]
  Fert -->|陽性| Family[家族遺傳評估]
  classDef ans fill:#d4edda,stroke:#27ae60,stroke-width:3px;
  class SMARCA4,Consol ans;

flowchart TD
  LGSC([Recurrent LGSC]) --> KRAS{KRAS mut?}
  KRAS -->|✅ KRAS mut| Avu[**Avutometinib + Defactinib**<br>v.3.2025 新核准]
  KRAS -->|wt 或 unknown| Other[MEKi Trametinib/Binimetinib<br>或 Hormone Letrozole/Anastrozole<br>或 Carbo+Pac]
  classDef ans fill:#d4edda,stroke:#27ae60,stroke-width:3px;
  class Avu ans;
